(function () {

    const buttons = document.querySelectorAll('[data-scroll]');

    buttons.forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.preventDefault();
            const id = btn.dataset.scroll;
            const section = document.getElementById(id);

            section.scrollIntoView({
                behavior: 'smooth',
                block: 'start'
            });
        });
    });
})()